const fs = require('fs');

function reverseNumber(n) {
    let sign = n < 0 ? -1 : 1;
    n = Math.abs(n);
    let rev = 0;

    while (n > 0) {
        rev = rev * 10 + (n % 10);
        n = Math.floor(n / 10);
    }

    return rev * sign;
}

const n = Number(fs.readFileSync(0, 'utf-8').trim());
console.log(reverseNumber(n));

