    public static String swapNumbers(int a, int b) {
        // Write your code here
        int temp = a;
        a = b;
        b = temp;
        return a + " " + b;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int a = sc.nextInt();
        int b = sc.nextInt();
        System.out.println(swapNumbers(a, b));
